AFTER:
    // scores — WARP-COALESCED K read, BIT-IDENTICAL dot.
    // One warp cooperates per key position. blockDim.x is a multiple of head_dim, and
    // head_dim in {64,128,256} is a multiple of 32, so blockDim.x % 32 == 0 and
    // n_warps = blockDim.x/32 warps stride the positions. Lane L loads d = L, L+32, ...
    // so the warp's simultaneous kp[L..L+31] are 32 consecutive f16 = 64 contiguous
    // bytes = one coalesced transaction (vs the old 128-byte-strided scalar row).
    // The dot is folded in STRICT ascending-d order (identical textual order to the
    // scalar kernel), so with --fmad=false the score bits are UNCHANGED.
    {
        const int n_warps = blockDim.x >> 5;
        const int warp_id = tid >> 5;
        const int lane    = tid & 31;
        for (int p = warp_id; p < position_count; p += n_warps) {
            const unsigned short* kp = kbase + (long)p * head_dim;
            // per-lane coalesced, f32-converted K: slot r holds conv(kp[r*32 + lane]).
            // slots array is compile-time-indexed below -> stays in registers, no smem,
            // no local spill. 8 slots supports head_dim up to 256; unused rounds DCE.
            float kreg[8];
            #pragma unroll
            for (int r = 0; r < 8; r++) {
                int d = (r << 5) + lane;
                kreg[r] = (d < head_dim) ? f16_bits_to_f32(kp[d]) : 0.0f;
            }
            // strict ascending-d fold: __shfl_sync gathers conv(kp[d]) from its owner
            // lane (d&31) out of its compile-time slot (d>>5). All 32 lanes run the
            // fold (shfl is warp-collective); only lane 0 stores. Bit-identical dot.
            float dot = 0.0f;
            #pragma unroll
            for (int r = 0; r < 8; r++) {
                int base = r << 5;
                if (base >= head_dim) break;
                for (int src = 0; src < 32; src++) {
                    int d = base + src;
                    if (d >= head_dim) break;
                    float v = __shfl_sync(0xffffffffu, kreg[r], src);
                    dot += qsh[d] * v;
                }
            }
            if (lane == 0) scores[p] = dot * scale;
        }
    }
    __syncthreads();

Key detail that keeps it register-resident (not local-memory spill): kreg is ALWAYS indexed
by the compile-time unroll variable r (never by a runtime d), so the fold uses __shfl_sync
to move the runtime-selected value between lanes rather than dynamically indexing the array.

