== NEW KERNEL (insert in KERNELS const, immediately AFTER attn_sk_partial, ~line 2199) ==

// Pass 2 (COALESCED variant, env-gated CAMELID_ATTN_COALESCED): same math role as
// attn_sk_partial but assigns ONE WARP per position-strip so each lane loads a uint (two
// consecutive f16 = 4 bytes); the warp's 32 uints = 128 contiguous bytes = one coalesced
// V-row transaction (vs the scalar kernel where only head_dim of 256 threads run the acc
// loop, 2 bytes each). All n_warps run parallel strided position subsets; each warp keeps
// register partials over ITS positions and the n_warps partials are combined in FIXED warp
// order (0..n_warps-1) -> deterministic FP reassociation of the chunk's p-sum (token-parity,
// NOT bit-identical to attn_sk_partial). Phase A (exp + ordered chunk exp-sum) is IDENTICAL
// to attn_sk_partial so lsum_buf and gmax stay byte-identical; only the weighted-V changes.
// Requires head_dim % 2 == 0 and head_dim <= 128 (covers the live 64/128); the launch keeps
// the scalar attn_sk_partial for anything else. block_dim must be a multiple of 32.
extern "C" __global__ void attn_sk_partial_coalesced(
    const unsigned short* __restrict__ cache_v, float* __restrict__ scores_buf,
    const float* __restrict__ chunkmax_buf, float* __restrict__ lsum_buf,
    float* __restrict__ acc_buf, int n_heads, int n_kv_heads, int head_dim,
    const int* __restrict__ position_ptr, int max_pos, int n_splits
) {
    int position_count = position_ptr[0] + 1;
    int head = blockIdx.x;
    int sp = blockIdx.y;
    if (head >= n_heads || sp >= n_splits) return;
    int repeats = n_heads / n_kv_heads;
    int kv_head = head / repeats;
    const unsigned short* vbase = cache_v + (long)kv_head * max_pos * head_dim;
    int p_lo = (int)((long)sp * position_count / n_splits);
    int p_hi = (int)((long)(sp + 1) * position_count / n_splits);
    float* sc_head = scores_buf + (long)head * max_pos;
    int tid = threadIdx.x;

    // ---- Phase A: exp(global max) + ordered chunk exp-sum. BYTE-IDENTICAL to attn_sk_partial.
    float gmax = -3.4e38f;
    for (int i = 0; i < n_splits; i++) gmax = fmaxf(gmax, chunkmax_buf[(long)head * n_splits + i]);
    for (int p = p_lo + tid; p < p_hi; p += blockDim.x) sc_head[p] = expf(sc_head[p] - gmax);
    __syncthreads();
    if (tid == 0) {
        float ls = 0.0f;
        for (int p = p_lo; p < p_hi; p++) ls += sc_head[p];
        lsum_buf[(long)head * n_splits + sp] = ls;
    }

    // ---- Phase B: COALESCED weighted-V (warp-per-position, uint loads, cross-warp combine).
    int n_warps = blockDim.x >> 5;
    int warp_id = tid >> 5;
    int lane = tid & 31;
    int ncol = head_dim >> 1;                 // # of uint (2xf16) columns per row (<=64 for hd<=128)
    float ae0 = 0.0f, ao0 = 0.0f;             // column lane      -> dims 2*lane, 2*lane+1
    float ae1 = 0.0f, ao1 = 0.0f;             // column lane+32   -> only exists when head_dim==128
    for (int p = p_lo + warp_id; p < p_hi; p += n_warps) {
        float sc = sc_head[p];                                        // uniform across warp (broadcast)
        const unsigned int* vrow = (const unsigned int*)(vbase + (long)p * head_dim);
        if (lane < ncol) {
            unsigned int packed = vrow[lane];                          // f16 bits for dims 2*lane, 2*lane+1
            ae0 += sc * f16_bits_to_f32((unsigned short)(packed & 0xffffu));
            ao0 += sc * f16_bits_to_f32((unsigned short)(packed >> 16));
        }
        if (lane + 32 < ncol) {
            unsigned int packed = vrow[lane + 32];
            ae1 += sc * f16_bits_to_f32((unsigned short)(packed & 0xffffu));
            ao1 += sc * f16_bits_to_f32((unsigned short)(packed >> 16));
        }
    }
    extern __shared__ float wpart[];          // launch sizes this to n_warps * head_dim floats
    if (lane < ncol) {
        wpart[warp_id * head_dim + (lane << 1)]     = ae0;
        wpart[warp_id * head_dim + (lane << 1) + 1] = ao0;
    }
    if (lane + 32 < ncol) {
        wpart[warp_id * head_dim + ((lane + 32) << 1)]     = ae1;
        wpart[warp_id * head_dim + ((lane + 32) << 1) + 1] = ao1;
    }
    __syncthreads();
    // Ordered cross-warp combine -> UNNORMALIZED chunk weighted-V, same acc_buf layout as scalar.
    for (int d = tid; d < head_dim; d += blockDim.x) {
        float a = 0.0f;
        for (int w = 0; w < n_warps; w++) a += wpart[w * head_dim + d];
        acc_buf[(((long)head * n_splits + sp) * head_dim) + d] = a;
    }
}

Notes on the snippet:
- No cuda_fp16.h and no make_float2 (unavailable in this NVRTC build): loads are plain `unsigned int` bit containers unpacked with the existing f16_bits_to_f32(). Keeps --fmad=false valid (no fmaf introduced).
- The two `if (lane < ncol)` / `if (lane+32 < ncol)` predicates are warp-UNIFORM for head_dim in {64,128}, so there is no branch divergence.
- No atomics -> the reduction is run-to-run deterministic (required by the parity gate).

